export function isPieceHanging(lastFen, fen, square) {
    let lastPiece = new Chess(lastFen).get(square);
    let piece = new Chess(fen).get(square);
    let attackers = getAttackers(fen, square);
    let defenders = getDefenders(fen, square);
    if (pieceValues[lastPiece.type] >= pieceValues[piece.type] && lastPiece.color != piece.color)
        return false; // it's a (winning) trade, not hanging
    if (piece.type == "r" && pieceValues[lastPiece.type] == 3
        && attackers.every(atk => pieceValues[atk.type] == 3) && attackers.length == 1)
        return false; // rook for minor exchange exception
    if (attackers.some(atk => pieceValues[atk.type] < pieceValues[piece.type])) return true;
    if (attackers.length > defenders.length) {
        let minAttackerValue = Math.min(...attackers.map(a => pieceValues[a.type]));
        if (pieceValues[piece.type] < minAttackerValue
            && defenders.some(dfn => pieceValues[dfn.type] < minAttackerValue)) return false;
        if (defenders.some(dfn => pieceValues[dfn.type] == 1)) return false; // pawn-defended
        return true;
    }
    return false;
}
